import{_ as a,o,c as l,ae as c}from"./chunks/framework.Czhw_PXq.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"releases/1.8.1.zh-CN.md","filePath":"releases/1.8.1.zh-CN.md"}'),d={name:"releases/1.8.1.zh-CN.md"};function i(t,e,r,s,n,h){return o(),l("div",null,[...e[0]||(e[0]=[c('<h3 id="核心亮点" tabindex="-1">核心亮点 <a class="header-anchor" href="#核心亮点" aria-label="Permalink to &quot;核心亮点&quot;">​</a></h3><p>这个补丁版本补上了 <code>1.8.0</code> 之后仍然存在的语言支持缺口。Notemd 现已完成所有已宣称支持的应用内 UI locale 的可见界面本地化收口，包括设置页、侧边栏动作、工作流构建器控件、原文提取设置、高级选项以及输出路径配置等界面，都应跟随 Obsidian 当前语言，而不是在正常使用中静默回退到英文。</p><p>同时，这一版也修正了文档契约。仓库根 README 与语言中心现在明确区分维护源文档、已发布 README 译文以及应用内 UI locale 的精确目录。English fallback 仍保留在实现中作为安全网，但不再被文档表述为受支持 locale 的常态路径。</p><h3 id="破坏性更新" tabindex="-1">破坏性更新 <a class="header-anchor" href="#破坏性更新" aria-label="Permalink to &quot;破坏性更新&quot;">​</a></h3><ul><li><strong>无需用户侧迁移操作</strong>：现有设置可继续使用，<code>uiLocale: auto</code> 仍然跟随 Obsidian。</li></ul><h3 id="新特性" tabindex="-1">新特性 <a class="header-anchor" href="#新特性" aria-label="Permalink to &quot;新特性&quot;">​</a></h3><ul><li><code>feat</code>: 补齐所有受支持 UI locale 在剩余设置项、工作流构建器、侧边栏提示、原文提取、高级设置与输出路径配置等可见界面上的本地化覆盖。</li><li><code>feat</code>: 新增工作流构建器、侧边栏提示、原文提取设置、剩余高级设置与通用输出路径界面的定向回归测试。</li><li><code>feat</code>: 更新语言中心，公开仓库中已发布的 README 译文集合，以及代码中精确的应用内 UI locale 目录。</li></ul><h3 id="bug-修复" tabindex="-1">Bug 修复 <a class="header-anchor" href="#bug-修复" aria-label="Permalink to &quot;Bug 修复&quot;">​</a></h3><ul><li><code>fix</code>: 修复了安装或更新后，部分已支持 locale 仍在某些设置项和侧边栏界面显示英文的问题，根因是这些可见界面仍存在遗漏的本地化项。</li><li><code>fix</code>: 修复了 README 与语言中心仍以“30+ 语言”笼统表述、未区分文档译文与应用内 UI locale 覆盖面的文档漂移问题。</li><li><code>fix</code>: 修复了语言支持说明中的契约偏差，明确 English fallback 是实现层安全网，而不是受支持可见界面的默认表现。</li></ul><h3 id="重构与杂项" tabindex="-1">重构与杂项 <a class="header-anchor" href="#重构与杂项" aria-label="Permalink to &quot;重构与杂项&quot;">​</a></h3><ul><li><code>docs</code>: 按当前代码现状对齐 <code>README.md</code>、<code>README_zh.md</code>、各语种 README 与语言中心。</li><li><code>chore</code>: 同步 <code>package.json</code>、<code>manifest.json</code>、<code>versions.json</code>、<code>change.md</code> 与 <code>1.8.1</code> 的发布元数据。</li><li><code>chore</code>: 将显式 UI locale 目录与 Obsidian 自动语言跟随模型，按 Notebook Navigator 的参考实践一并写入文档约束。</li></ul><h3 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h3><p>感谢 <code>@Jacobinwwey</code> 完成受支持 locale 的 UI 收口、文档契约校准与 <code>1.8.1</code> 补丁版本发布准备。</p>',13)])])}const f=a(d,[["render",i]]);export{_ as __pageData,f as default};
